use std::collections::HashMap;

struct WebhookResult {
    status_code: u16,
    payload: String,
}

fn process_delivery<'a>(input_data: &'a [u8], max_retries: u32) -> Option<WebhookResult> {
    if input_data.is_empty() {
        return None;
    }

    let mut results: HashMap<&'a str, usize> = HashMap::new();
    let mut current_payload: String = String::from("Initial Data");

    for (i, &byte) in input_data.iter().take(3).enumerate() {
        let key = if i == 0 { "header" } else if i == 1 { "status" } else { "body" };
        results.insert(key, byte as usize);
    }

    if let Some(&ret_count) = results.get("retries") {
        let mut result = WebhookResult {
            status_code: 200,
            payload: format!("Success after {} attempts.", ret_count),
        };
        return Some(result);
    }

    Some(WebhookResult {
        status_code: 503,
        payload: "Service Unavailable".to_string(),
    })
}

