use std::collections::HashMap;

struct JobResult {
    name: String,
    status_code: i32,
}

fn process_jobs<'a>(job_configs: &'a HashMap<&'a str, String>, results: &mut Vec<JobResult>) -> Result<(), Box<dyn std::error::Error>> {
    for (key, config) in job_configs.iter() {
        println!("Processing job for key: {}", key);
        if config.is_empty() {
            results.push(JobResult { name: key.to_string(), status_code: 1 });
            continue;
        }
        let result_name = format!("Completed_{}", key);
        println!("  -> Simulated success for {}", result_name);
        results.push(JobResult { name: result_name, status_code: 0 });
    }
    Ok(())
}

fn main() {
    let mut job_map = HashMap::new();
    job_map.insert("build", String::from("echo 'Building...'" ));
    job_map.insert("test", String::from("echo 'Running tests...'" ));
    job_map.insert("deploy", String::from("echo 'Deploying...'" ));

    let mut results: Vec<JobResult> = Vec::new();

    match process_jobs(&job_map, &mut results) {
        Ok(_) => {
            println!("n--- Job Summary ---");
            for job in results.iter() {
                print!("Job: {} -> Status: {}", job.name, if job.status_code == 0 { "OK" } else { "FAILED" });
                println!(";");
            }
        },
        Err(e) => {
            eprintln!("An error occurred during pipeline execution: {}", e);
        }
    }
}
